DEFAULTS: Dict[str, object] = _DEFAULTS_TEMPLATE.copy()


def create_config(overrides: Optional[Mapping[str, object]] = None) -> Dict[str, object]:
    """Return a new config dict based on DEFAULTS, merged with any overrides.

    This function returns a shallow copy so callers can modify the result without
    affecting the module-level DEFAULTS.

    Args:
        overrides: Optional mapping of keys to override in the defaults.

    Raises:
        TypeError: if overrides is provided but is not a mapping.
    """
    config = DEFAULTS.copy()
    if overrides:
        if not isinstance(overrides, Mapping):
            raise TypeError(f"overrides must be a mapping, got {type(overrides)!r}")
        config.update(overrides)
    return config


def reset_defaults() -> None:
    """Restore DEFAULTS to the original factory values from the template."""
    global DEFAULTS
    DEFAULTS = _DEFAULTS_TEMPLATE.copy()
